package cn.org.starpivot.ai.domain.entity;import com.baomidou.mybatisplus.annotation.IdType;import com.baomidou.mybatisplus.annotation.TableId;import com.baomidou.mybatisplus.annotation.TableLogic;import com.baomidou.mybatisplus.annotation.TableName;import lombok.Data;import java.time.LocalDateTime;@Data@TableName("ai_knowledge_document")public class AiKnowledgeDocument {    @TableId(type = IdType.AUTO)    private Long docId;    private Long kbId;    private String title;    private String content;    /** TEXT / FILE */    private String sourceType;    private String originalFileName;    private String fileType;    private Long fileSize;    private String objectName;    private Integer chunkCount;    /** PENDING / PROCESSING / DONE / FAILED */    private String indexStatus;    private String errorMsg;    private Integer docVersion;    private LocalDateTime indexedAt;    private String status;    @TableLogic    private String delFlag;    private String createBy;    private LocalDateTime createTime;    private String updateBy;    private LocalDateTime updateTime;}